// Helper to efficiently convert 4 packed FP8 (e4m3) bytes into 4 FP32 floats
inline __device__ float4 cvt_fp8x4_to_float4(uint32_t val) {
    float4 res;
    const uint8_t* bytes = reinterpret_cast<const uint8_t*>(&val);
    res.x = float(reinterpret_cast<const __nv_fp8_e4m3&>(bytes[0]));
    res.y = float(reinterpret_cast<const __nv_fp8_e4m3&>(bytes[1]));
    res.z = float(reinterpret_cast<const __nv_fp8_e4m3&>(bytes[2]));
    res.w = float(reinterpret_cast<const __nv_fp8_e4m3&>(bytes[3]));
    return res;
}

